-- Scenario 1: 214 Thornberry Drive, Simpsonville — Logistics Employment Growth Driver (Thornberry Commons)
-- Category M2-S6-C1 #1 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'introductory',
  '214 Thornberry Drive, Simpsonville — Logistics Employment Growth Driver (Thornberry Commons)',
  'You are appraising the property at 214 Thornberry Drive, Simpsonville, SC 29681 (3BR/2BA, 1,840 SF, built 2009, brick-front ranch · Thornberry Commons). You are appraising a single-family residence for mortgage lending purposes. Your client is a GSE-approved lender. Your analysis must support the market conditions section of the URAR and be consistent with Fannie Mae 1004MC requirements. Section 6 — Market Analysis — requires you to identify which market indicators and external factors are present in the data package, classify each present indicator as Improving, Stable, Declining, or Market-Dependent based on the indicator data and external context, and write a market-supported rationale citing specific data from the indicator table or external context. Indicators not evidenced in the data package must be left unchecked. Every classification must be grounded in specific evidence — this assignment evaluates evidence-based market analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S6-C1';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "214 Thornberry Drive, Simpsonville, SC 29681", "subject_summary": "3BR/2BA, 1,840 SF, built 2009, brick-front ranch · Thornberry Commons", "school": "Greenville County - Hillcrest HS zone", "effective_date": "Current (purchase appraisal)", "context_label": "Lending Context", "context_text": "You are appraising a single-family residence for mortgage lending purposes. Your client is a GSE-approved lender. Your analysis must support the market conditions section of the URAR and be consistent with Fannie Mae 1004MC requirements."}, "tables": [{"label": "", "cols": ["Indicator", "Prior 7-12 Months", "Current 1-6 Months"], "rows": [["Closed Sales (subdivision + 1-mile radius)", "38", "47"], ["Active Listings", "9", "5"], ["Median Days on Market", "31", "18"], ["Median Sale Price", "$284,500", "$301,200"], ["List-to-Sale Price Ratio", "98.4%", "101.2%"], ["Absorption Rate", "4.2 months", "1.9 months"]]}], "external": "The Greenville-Spartanburg MSA added approximately 3,200 net jobs in manufacturing and logistics over the past 12 months, with a large announced distribution facility in Fountain Inn drawing relocation buyers into the Simpsonville corridor.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "emp", "label": "Employment/relocation demand driver"}, {"id": "sea", "label": "Seasonal demand pattern"}, {"id": "new", "label": "New construction pipeline"}], "net_conclusion": "Seller''s market, improving conditions. All six present indicators align with no conflicting signals. A positive time adjustment is supported.", "commentary": "At the introductory level, students should recognize a clean, unambiguous seller''s market. Every quantitative indicator points the same direction. The two distractors test whether students add factors not evidenced in the data - a common USPAP compliance error. On the Fannie Mae 1004MC, all six indicator categories have designated fields; checking unsupported boxes creates lender compliance exposure.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Improving", "rationale": "Dropped from 4.2 to 1.9 months - well below the 3-month seller''s market threshold. This is the single most important GSE market condition indicator and is required on the Fannie Mae 1004MC."}, "dom": {"present": true, "classification": "Improving", "rationale": "DOM fell from 31 to 18 days, confirming accelerating demand. Faster absorption directly supports upward price pressure and must be reported on the 1004MC."}, "lts": {"present": true, "classification": "Improving", "rationale": "Crossed above 100% (98.4 to 101.2%). Buyers bidding over asking price is a clear seller''s market indicator and a required 1004MC field."}, "msp": {"present": true, "classification": "Improving", "rationale": "Rose 5.9% in six months. Upward price pressure, combined with demand indicators, confirms that a positive time adjustment is supported."}, "inv": {"present": true, "classification": "Improving", "rationale": "Active listings fell from 9 to 5. Constrained supply with rising demand is the classic seller''s market supply-demand imbalance."}, "emp": {"present": true, "classification": "Improving", "rationale": "The announced distribution facility in Fountain Inn is generating relocation demand directly into the Simpsonville corridor - an external factor with documented, verifiable support."}, "sea": {"present": false, "rationale": "No seasonal data was provided in this package. Including a factor without evidentiary support is a USPAP compliance issue - appraisers must only cite factors they can support with data."}, "new": {"present": false, "rationale": "No new construction data was provided. This is a deliberate distractor - appraisers must not cite factors they cannot support with verifiable data from the defined market area."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'market_indicator_analysis'
WHERE sc.code = 'M2-S6-C1'
  AND s.order_index = 1;

