FROM scenario_categories WHERE code = 'M2-S6-C1';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "408 Millstone Court, Duncan, SC 29334", "subject_summary": "3BR/2BA, 1,620 SF, built 2004, vinyl-sided ranch · Millstone Creek", "school": "Spartanburg County School District 5", "effective_date": "Current (purchase appraisal)", "context_label": "Lending Context", "context_text": "You are appraising a single-family residence for a GSE lender. The subject is in an entry-level price range in a Spartanburg County suburb. Your analysis must support the market conditions section of the URAR and comply with Fannie Mae 1004MC requirements."}, "tables": [{"label": "", "cols": ["Indicator", "Prior 7-12 Months", "Current 1-6 Months"], "rows": [["Closed Sales (subdivision + 1-mile radius)", "22", "14"], ["Active Listings", "8", "15"], ["Median Days on Market", "28", "52"], ["Median Sale Price", "$198,500", "$191,200"], ["List-to-Sale Price Ratio", "97.8%", "95.4%"], ["Absorption Rate", "2.8 months", "5.9 months"]]}], "external": "A major employer in the Duncan/Wellford corridor announced a workforce reduction of approximately 800 positions, reducing demand for entry-level housing in this price range.", "factors": [{"id": "abs", "label": "Absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "emp", "label": "Employment/workforce reduction"}, {"id": "int", "label": "Interest rate environment"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "Buyer''s market, declining conditions. All six present indicators align - closed sales falling, inventory rising, DOM nearly doubled, prices declining. A negative time adjustment is likely supported.", "commentary": "Scenario 2 presents the mirror image of Scenario 1 - a clean, unambiguous buyer''s market. Students must recognize that all quantitative indicators move together and that the employment shock is a material external factor requiring citation. On the 1004MC, the Declining designation triggers additional lender scrutiny and requires particularly strong written support in the appraisal narrative.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"abs": {"present": true, "classification": "Declining", "rationale": "Rose from 2.8 to 5.9 months - approaching buyer''s market territory (above 6 months). Combined with all other indicators, this confirms a declining market designation on the 1004MC."}, "dom": {"present": true, "classification": "Declining", "rationale": "Nearly doubled from 28 to 52 days. Homes sitting this much longer indicate materially weakening buyer demand."}, "lts": {"present": true, "classification": "Declining", "rationale": "Fell from 97.8% to 95.4% - buyers negotiating larger concessions. This directional decline confirms softening demand and negotiating leverage shifting to buyers."}, "msp": {"present": true, "classification": "Declining", "rationale": "Fell 3.7% over six months. Actual price decline is one of the strongest declining market signals. The 1004MC must reflect this and will trigger enhanced underwriting review."}, "inv": {"present": true, "classification": "Declining", "rationale": "Active listings nearly doubled from 8 to 15. Rising unsold inventory is a leading indicator of further price softening and extended marketing times."}, "emp": {"present": true, "classification": "Declining", "rationale": "800-position reduction directly reduces the buyer pool for entry-level product in this corridor. This external factor must be cited with a verifiable, published source."}, "int": {"present": false, "rationale": "No interest rate data was included in this package. Citing interest rates without data support would be speculative. Do not introduce factors not evidenced in the data."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor - never include factors without evidentiary support in the data package."}}}'::jsonb
