  '{"subject": {"address_summary": "5519 Verdae Boulevard, Greenville, SC 29607", "subject_summary": "4BR/3.5BA, 3,240 SF, built 2014, golf course community · Verdae Greens", "school": "Greenville County - J.L. Mann HS zone", "effective_date": "Current (purchase appraisal)", "context_label": "Lending Context", "context_text": "You are appraising a golf course community property for a GSE lender. Two data sets are provided: broad market data for the Greenville County $350K-$500K price range, and submarket data for the Verdae Greens corridor. Your analysis must determine the appropriate market area, identify the divergence, and support a defensible market condition conclusion."}, "tables": [{"label": "", "cols": ["Indicator", "Broad Market (Prior 7-12 Mo.)", "Broad Market (Current 1-6 Mo.)", "Submarket (Prior 7-12 Mo.)", "Submarket (Current 1-6 Mo.)"], "rows": [["Closed Sales", "312", "298", "14", "9"], ["Active Listings", "89", "107", "3", "8"], ["Median Days on Market", "21", "29", "18", "47"], ["Median Sale Price", "$412,000", "$418,500", "$441,000", "$428,500"], ["List-to-Sale Price Ratio", "100.8%", "99.4%", "100.2%", "96.8%"], ["Absorption Rate", "2.8 months", "4.3 months", "1.9 months", "8.9 months"]]}], "external": "The golf course amenity association announced a membership fee increase of $4,200 annually, dampening demand among buyers who purchased primarily for golf access. A mixed-use commercial development has been approved on an adjacent Verdae Boulevard parcel; some prospective buyers have cited concerns about the character impact on the neighborhood. Greenville County employment remains broadly stable.", "factors": [{"id": "b_abs", "label": "Broad market absorption rate trend"}, {"id": "b_dom", "label": "Broad market days on market trend"}, {"id": "b_lts", "label": "Broad market list-to-sale ratio trend"}, {"id": "s_abs", "label": "Submarket absorption rate trend"}, {"id": "s_dom", "label": "Submarket days on market trend"}, {"id": "s_lts", "label": "Submarket list-to-sale ratio trend"}, {"id": "s_msp", "label": "Submarket median sale price trend"}, {"id": "golf", "label": "Golf course amenity cost increase"}, {"id": "comm", "label": "Adjacent commercial development"}, {"id": "emp", "label": "Employment environment"}, {"id": "int", "label": "Interest rate environment"}, {"id": "sea", "label": "Seasonal demand pattern"}], "net_conclusion": "The appropriate market area is the submarket - Verdae Greens and the immediate corridor. Submarket conditions are declining significantly, diverging materially from a merely softening broad market. A meaningful negative time adjustment is warranted and must be supported by submarket data, not broad market data.", "commentary": "Scenario 9 is the most technically demanding standard GSE scenario. The critical skill is recognizing that when a submarket diverges materially from the broader market, the submarket data controls. Using broad market data to support a less-negative conclusion would be a USPAP compliance failure - the appraiser must use data representing the competitive market for the subject. The golf course fee increase and commercial development explain the divergence and must be identified as submarket-specific external factors.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"b_abs": {"present": true, "classification": "Declining", "rationale": "Broad market moved from 2.8 to 4.3 months - transitioning from seller''s toward balanced. The broader Greenville $350K-$500K market is softening but not severely."}, "b_dom": {"present": true, "classification": "Declining", "rationale": "DOM increased from 21 to 29 days in the broad market - softening, but modest compared to the submarket divergence."}, "b_lts": {"present": true, "classification": "Declining", "rationale": "Dropped from 100.8% to 99.4% in the broad market - mild softening, consistent with the transitioning broad market picture."}, "s_abs": {"present": true, "classification": "Declining", "rationale": "Submarket absorption exploded from 1.9 to 8.9 months - a shift from strong seller''s to deep buyer''s market territory. This is dramatically worse than the broad market and is the critical analytical finding."}, "s_dom": {"present": true, "classification": "Declining", "rationale": "Submarket DOM jumped from 18 to 47 days - a 161% increase. Homes in Verdae Greens are sitting nearly three times longer. The magnitude of this divergence from the broad market is material."}, "s_lts": {"present": true, "classification": "Declining", "rationale": "Dropped from 100.2% to 96.8% - sellers are now negotiating significantly below asking price. This is a strong buyer''s market signal specific to the submarket."}, "s_msp": {"present": true, "classification": "Declining", "rationale": "Actual submarket price declined from $441,000 to $428,500 - a -3.1% drop while broad market prices rose +1.6%. This submarket divergence is material evidence for a negative time adjustment."}, "golf": {"present": true, "classification": "Declining", "rationale": "A $4,200 annual fee increase directly reduces the buyer pool willing to absorb this cost. A submarket-specific external factor with a clear, negative demand impact on golf-dependent properties."}, "comm": {"present": true, "classification": "Declining", "rationale": "Buyer hesitation over commercial character impact is a documented external factor specific to this submarket. Appropriate to include and supported by buyer feedback."}, "emp": {"present": false, "rationale": "Employment is broadly stable and not an active driver of the divergence between broad and submarket conditions. Do not cite neutral background factors as active market signals."}, "int": {"present": false, "rationale": "If rates were the driver, broad and submarket would move in the same direction - they are not. The divergence is submarket-specific. No rate data was provided."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'market_indicator_analysis'
WHERE sc.code = 'M2-S6-C1'
  AND s.order_index = 9;

