-- Category M2-S6-C1 #10 · difficulty 'expert'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 10,
  'expert',
  '8847 Augusta Road, Lyman — BMW Expansion with Apartment Competition (Augusta Ridge)',
  'You are appraising the property at 8847 Augusta Road, Lyman, SC 29365 (4BR/2.5BA, 2,210 SF, built 2018, craftsman two-story · Augusta Ridge). You are completing a purchase appraisal for a GSE lender. Two data sets are provided - broad Spartanburg County market data and subject-area data for the Lyman/Duncan corridor. You must synthesize both data sets, evaluate leading and lagging indicators, identify all external factors, and write a complete, USPAP-compliant market condition narrative sufficient to support your time adjustment conclusion. Section 6 — Market Analysis — requires you to identify which market indicators and external factors are present in the data package, classify each present indicator as Improving, Stable, Declining, or Market-Dependent based on the indicator data and external context, and write a market-supported rationale citing specific data from the indicator table or external context. Indicators not evidenced in the data package must be left unchecked. Every classification must be grounded in specific evidence — this assignment evaluates evidence-based market analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S6-C1';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "8847 Augusta Road, Lyman, SC 29365", "subject_summary": "4BR/2.5BA, 2,210 SF, built 2018, craftsman two-story · Augusta Ridge", "school": "Spartanburg County District 5 - Byrnes HS zone", "effective_date": "Current (purchase appraisal)", "context_label": "Lending Context", "context_text": "You are completing a purchase appraisal for a GSE lender. Two data sets are provided - broad Spartanburg County market data and subject-area data for the Lyman/Duncan corridor. You must synthesize both data sets, evaluate leading and lagging indicators, identify all external factors, and write a complete, USPAP-compliant market condition narrative sufficient to support your time adjustment conclusion."}, "tables": [{"label": "", "cols": ["Indicator", "Broad County (Prior 7-12 Mo.)", "Broad County (Current 1-6 Mo.)", "Subject Area (Prior 7-12 Mo.)", "Subject Area (Current 1-6 Mo.)"], "rows": [["Closed Sales", "187", "201", "31", "38"], ["Active Listings", "52", "41", "14", "9"], ["Median Days on Market", "27", "22", "24", "17"], ["Median Sale Price", "$238,500", "$244,800", "$229,400", "$241,100"], ["List-to-Sale Price Ratio", "99.2%", "100.4%", "98.9%", "101.3%"], ["Absorption Rate", "3.7 months", "3.1 months", "3.1 months", "2.1 months"]]}], "external": "BMW Plant expansion announced for 2026 is expected to add approximately 2,800 positions in the $55K-$75K wage range - directly feeding demand in the $220K-$270K price range. A new 312-unit apartment complex opened in Greer and may reduce rental-to-purchase conversion demand at the margins. Mortgage rates stabilized after prior increases, easing affordability pressure. The Lyman/Duncan corridor has been identified in the SCDOT infrastructure improvement plan for roadway upgrades over the next five years.", "factors": [{"id": "b_abs", "label": "Broad county absorption rate trend"}, {"id": "s_abs", "label": "Subject area absorption rate trend"}, {"id": "dom", "label": "Days on market trend"}, {"id": "lts", "label": "List-to-sale price ratio trend"}, {"id": "msp", "label": "Median sale price trend"}, {"id": "inv", "label": "Active listing inventory level"}, {"id": "bmw", "label": "BMW expansion employment driver"}, {"id": "apt", "label": "New apartment complex opening"}, {"id": "rate", "label": "Interest rate stabilization"}, {"id": "infra", "label": "SCDOT infrastructure improvement plan"}, {"id": "sea", "label": "Seasonal demand pattern"}, {"id": "neg", "label": "Employment reduction/layoff"}], "net_conclusion": "Strong improving market in the subject area, outperforming the already-improving county average. A positive time adjustment is supported and well-documented. The narrative should reference BMW expansion as a leading demand driver, note the apartment complex as a modest moderating factor, and acknowledge rate stabilization as a supportive condition.", "commentary": "Scenario 10 is the capstone GSE scenario. Students must synthesize two aligned data sets, evaluate both current and forward-looking indicators, and produce a complete market condition narrative. Key skills: (1) recognizing the subject area is outperforming the broad market positively - not diverging negatively as in Scenario 9; (2) classifying BMW expansion as a leading indicator, not a current data point; and (3) identifying the apartment complex as a real but uncertain moderating factor. Expert-level appraisers integrate all threads into a single, coherent, defensible narrative.", "classification_options": ["Improving", "Stable", "Declining", "Market-Dependent"], "min_rationale_chars": 20}'::jsonb,
  '{"factors": {"b_abs": {"present": true, "classification": "Improving", "rationale": "Moved from 3.7 to 3.1 months - improving within the balanced range. The broad county market is tightening modestly and confirms the subject area improvement is not isolated."}, "s_abs": {"present": true, "classification": "Improving", "rationale": "Dropped from 3.1 to 2.1 months - crossed into seller''s market territory. The subject area is outperforming the county average, which is a positive submarket signal."}, "dom": {"present": true, "classification": "Improving", "rationale": "DOM fell from 24 to 17 days in the subject area - a 29% reduction. Homes selling faster confirms demand acceleration specific to this corridor."}, "lts": {"present": true, "classification": "Improving", "rationale": "Rose from 98.9% to 101.3% in the subject area - crossed above asking price. Buyers competing and bidding over list is a strong seller''s market confirmation."}, "msp": {"present": true, "classification": "Improving", "rationale": "+5.1% in the subject area over six months. Strong appreciation in a workforce price range confirms demand-driven upward pressure."}, "inv": {"present": true, "classification": "Improving", "rationale": "Subject area active listings fell from 14 to 9 - a 36% reduction. Tightening supply paired with rising demand confirms the seller''s market designation."}, "bmw": {"present": true, "classification": "Improving", "rationale": "2,800 announced positions in the $55K-$75K wage band are a leading indicator of near-term demand growth in the $220K-$270K price range. A documented, verifiable external factor with direct price range alignment."}, "apt": {"present": true, "classification": "Market-Dependent", "rationale": "312 new units could absorb some rental-to-purchase conversion demand that would otherwise enter the for-sale market. Real and documented, but net impact is uncertain. Market-Dependent is appropriate."}, "rate": {"present": true, "classification": "Improving", "rationale": "Rate stabilization after prior increases is a positive affordability signal - buyers who had paused can re-engage. A modest but real improving factor at the margins."}, "infra": {"present": true, "classification": "Improving", "rationale": "Long-term roadway upgrades to the Lyman/Duncan corridor support neighborhood trajectory and accessibility over a multi-year horizon. A leading indicator appropriately noted with a longer time frame."}, "sea": {"present": false, "rationale": "No seasonal data was provided. This is a distractor."}, "neg": {"present": false, "rationale": "No employment reduction was identified. The BMW expansion is the relevant employment factor. Do not introduce negative employment factors not present in the data."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
